module div_8bit (
    input clk, rst, sign, opn_valid, res_ready,
    input [7:0] dividend, divisor,
    output reg res_valid,
    output reg [15:0] result
);
    reg [7:0] dividend_reg, divisor_reg;
    reg [15:0] SR;
    reg [3:0] cnt;
    reg [3:0] start_cnt;
    reg [7:0] NEG_DIVISOR;
    reg res_ready_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 0;
            res_ready_reg <= 0;
        end
        else begin
            if (opn_valid && !res_valid) begin
                dividend_reg <= dividend;
                divisor_reg <= divisor;
                SR <= {1'b0, dividend_reg};
                NEG_DIVISOR <= sign ? -divisor_reg : divisor_reg;
                cnt <= 1;
                start_cnt <= 1;
            end
            else if (start_cnt) begin
                if (cnt == 8) begin
                    cnt <= 0;
                    start_cnt <= 0;
                    result <= SR;
                end
                else begin
                    cnt <= cnt + 1;
                    {SR, res_ready_reg} <= {SR[14:0], 1'b0};
                    if (SR[15:8] >= NEG_DIVISOR) begin
                        {SR[15:8], SR[7:0]} <= {SR[15:8] - NEG_DIVISOR, SR[7:0], 1'b1};
                    end
                end
            end
            else begin
                res_ready_reg <= res_ready;
                if (cnt == 8 && res_ready) begin
                    res_valid <= 0;
                end
                else if (res_valid && res_ready_reg) begin
                    res_valid <= 0;
                end
            end
        end
    end
endmodule
